import React, { useState, useEffect, useCallback } from 'react';
import { api } from '../services/api'; 
import { useAuth } from '../context/AuthContext';
import { MapPin, CheckCircle, Truck, Loader2, Bike, Store, XCircle, AlertTriangle } from 'lucide-react';

const MisPedidosCliente = () => {
  const [pedidos, setPedidos] = useState([]);
  const [loading, setLoading] = useState(true);
  const [errorConexion, setErrorConexion] = useState(false);
  const [progresoEnvio, setProgresoEnvio] = useState({}); 
  const { user } = useAuth();

  const fetchPedidos = useCallback(async () => {
    try {
      setLoading(true);
      setErrorConexion(false);
      const clienteId = user?.id || user?._id;
      if (!clienteId) return;
      
      const data = await api.getPedidosCliente(clienteId);
      setPedidos(Array.isArray(data) ? data : []);
    } catch (error) {
      console.error("Error al obtener historial:", error);
      setErrorConexion(true);
    } finally {
      setLoading(false);
    }
  }, [user]);

  useEffect(() => {
    if (user) fetchPedidos();
  }, [user, fetchPedidos]);

  useEffect(() => {
    pedidos.forEach(pedido => {
      if (pedido.estado?.toLowerCase() === 'camino' && !progresoEnvio[pedido._id]) {
        let progreso = 0;
        const interval = setInterval(() => {
          progreso += 1;
          setProgresoEnvio(prev => ({ ...prev, [pedido._id]: progreso }));
          if (progreso >= 100) clearInterval(interval);
        }, 300); 
      }
    });
  }, [pedidos]);

  const handleCancelar = async (pedidoId) => {
    if (!window.confirm("¿Deseas cancelar este pedido?")) return;
    try {
      await api.cancelarPedido(pedidoId);
      fetchPedidos(); 
    } catch (err) {
      alert("Error: " + err.message);
    }
  };

  if (errorConexion) return (
    <div style={msgContainer}>
      <AlertTriangle size={50} color="#ef4444" />
      <h3>Error de conexión</h3>
      <p>No se pudo conectar con el servidor.</p>
      <button onClick={fetchPedidos} style={retryButton}>Reintentar</button>
    </div>
  );

  if (loading) return (
    <div style={msgContainer}>
      <Loader2 size={40} className="animate-spin" color="#3182ce" />
      <p>Consultando pedidos...</p>
    </div>
  );

  return (
    <div style={container}>
      <h2 style={title}>Seguimiento en Vivo</h2>
      <div style={listContainer}>
        {pedidos.map((pedido) => {
          const estado = pedido.estado?.toLowerCase();
          const p = progresoEnvio[pedido._id] || (estado === 'completado' ? 100 : 0);
          const puedeCancelar = estado === 'pendiente' || estado === 'proceso';

          return (
            <div key={pedido._id} style={{...orderCard, opacity: estado === 'cancelado' ? 0.6 : 1}}>
              <div style={orderHeader}>
                <span style={dateText}>#{pedido._id?.slice(-5)}</span>
                <span style={{...statusText, color: estado === 'cancelado' ? '#ef4444' : '#3182ce'}}>
                  {estado === 'cancelado' ? 'CANCELADO' : (p === 100 ? 'ENTREGADO' : estado.toUpperCase())}
                </span>
              </div>

              {estado !== 'cancelado' && (
                <div style={stepperWrapper}>
                  <div style={stepperBackground}><div style={{...stepperFill, width: `${p}%`}} /></div>
                  <div style={nodesContainer}>
                    <div style={nodeGroup}>
                        <div style={{...node, backgroundColor: p >= 5 ? '#3182ce' : '#e2e8f0'}}><Store size={14} color="white" /></div>
                        <span style={nodeLabel}>Local</span>
                    </div>
                    <div style={nodeGroup}>
                        <div style={{...node, backgroundColor: p >= 50 ? '#3182ce' : '#e2e8f0'}}><Bike size={14} color="white" /></div>
                        <span style={nodeLabel}>Camino</span>
                    </div>
                    <div style={nodeGroup}>
                        <div style={{...node, backgroundColor: p >= 100 ? '#22c55e' : '#e2e8f0'}}><CheckCircle size={14} color="white" /></div>
                        <span style={nodeLabel}>Llegó</span>
                    </div>
                  </div>
                  {p > 0 && p < 100 && <div style={{...truckFloat, left: `calc(${p}% - 15px)`}}><Truck size={18} color="#3182ce" /></div>}
                </div>
              )}

              <div style={bodyCard}>
                <h4 style={localName}>{pedido.local?.nombre}</h4>
                <div style={itemsBox}>
                  {pedido.items?.map((it, i) => (
                    <div key={i} style={itemLine}><span>{it.cantidad}x {it.productoNombre}</span><span>${it.precio * it.cantidad}</span></div>
                  ))}
                </div>
                <div style={priceRow}><strong>Total</strong><strong>${pedido.total}</strong></div>
                {puedeCancelar && (
                  <button onClick={() => handleCancelar(pedido._id)} style={cancelButton}><XCircle size={16} /> Cancelar</button>
                )}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const container = { padding: '20px', maxWidth: '500px', margin: '0 auto', fontFamily: 'sans-serif' };
const title = { fontSize: '1.5rem', fontWeight: '800', marginBottom: '20px' };
const listContainer = { display: 'flex', flexDirection: 'column', gap: '20px' };
const orderCard = { background: '#fff', borderRadius: '20px', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', border: '1px solid #eee', overflow: 'hidden' };
const orderHeader = { padding: '15px 20px', display: 'flex', justifyContent: 'space-between', background: '#f8fafc' };
const dateText = { color: '#94a3b8', fontSize: '0.8rem' };
const statusText = { fontSize: '0.8rem', fontWeight: 'bold' };
const stepperWrapper = { padding: '30px 40px 15px', position: 'relative' };
const stepperBackground = { height: '4px', background: '#f1f5f9', borderRadius: '10px' };
const stepperFill = { height: '100%', background: '#3182ce', transition: 'width 0.3s' };
const nodesContainer = { position: 'absolute', top: '20px', left: '40px', right: '40px', display: 'flex', justifyContent: 'space-between' };
const nodeGroup = { display: 'flex', flexDirection: 'column', alignItems: 'center', gap: '5px' };
const node = { width: '25px', height: '25px', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const nodeLabel = { fontSize: '0.6rem', fontWeight: 'bold', color: '#64748b' };
const truckFloat = { position: 'absolute', top: '8px', background: 'white', borderRadius: '50%', padding: '3px', boxShadow: '0 2px 5px rgba(0,0,0,0.1)' };
const bodyCard = { padding: '20px' };
const localName = { margin: '0 0 10px 0', fontSize: '1rem' };
